# Define page functions
def dashboard():
    st.title('Dashboard')

def profile():
    st.title('Profile')

def admin():
    st.title('Admin')

def login():
    st.title('Login')

if st.session_state.get('logged_in'):
    pages = {
        'Dashboard': st.Page(dashboard),
        'Profile': st.Page(profile),
        'Admin': st.Page(admin)
    }
else:
    pages = {
        'Login': st.Page(login)
    }

pg = st.navigation(pages)
pg.run()

grouped_navigation.code:
# Define page functions
def home():
    st.title('🏠 Welcome')

def upload():
    st.title('📤 Upload')

def analyze():
    st.title('📊 Analyze')

def export():
    st.title('📥 Export')

def profile():
    st.title('👤 Profile')

def preferences():
    st.title('⚙️ Preferences')

# Group pages by section
pages = {
    'Home': [
        st.Page(home, title='Welcome', icon='🏠')
    ],
    'Data': [
        st.Page(upload, title='Upload', icon='📤'),
        st.Page(analyze, title='Analyze', icon='📊'),
        st.Page(export, title='Export', icon='📥')
    ],
    'Settings': [
        st.Page(profile, title='Profile', icon='👤'),
        st.Page(preferences, title='Preferences', icon='⚙️')
    ]
}

pg = st.navigation(pages)
pg.run()
